+        let map = DoomMap {
+            name: "LEFT".into(),
+            vertices: vec![],
+            linedefs: vec![],
+            sidedefs: vec![],
+            sectors: vec![],
+            segs: vec![],
+            subsectors: vec![
+                SubSector {
+                    num_segs: 0,
+                    first_seg: 0,
